import React, { useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';

const BusinessDetails = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { squareNumber, duration, pageNumber } = location.state || {};
  
  const [businessName, setBusinessName] = useState('');
  const [contactEmail, setContactEmail] = useState('');
  const [dealLink, setDealLink] = useState('');
  const [logoData, setLogoData] = useState(null);
  const [isFormValid, setIsFormValid] = useState(false);

  // SIMPLE VALIDATION: Only business name, email, and logo are required
  const validateForm = () => {
    const isValid = businessName.trim().length > 0 && 
                   contactEmail.trim().length > 0 && 
                   logoData !== null;
    
    console.log('✅ Validation:', {
      businessName: businessName.length > 0,
      email: contactEmail.length > 0, 
      logo: logoData !== null,
      isValid: isValid
    });
    
    setIsFormValid(isValid);
  };

  const previewLogo = (event) => {
    const file = event.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        alert('File size must be less than 2MB');
        return;
      }
      
      const reader = new FileReader();
      reader.onload = function(e) {
        setLogoData(e.target.result);
        validateForm();
      }
      reader.readAsDataURL(file);
    }
  };

  const handleContinue = () => {
    if (!isFormValid) {
      alert('Please complete all required fields: Business Name, Email, and Logo');
      return;
    }

    const purchaseData = {
      squareNumber,
      duration,
      pageNumber,
      businessName,
      contactEmail,
      dealLink: dealLink, // Keep whatever they entered, even if empty
      logoData
    };
    
    console.log('Proceeding to checkout with:', purchaseData);
    navigate('/checkout', { state: purchaseData });
  };

  const totalAmount = duration;

  return (
    <div className="checkout-container">
      <div className="checkout-header">
        <h1>🛍️ Business & Advertisement Details</h1>
        <p>Complete your advertising campaign setup</p>
      </div>

      <div className="checkout-content">
        {/* Order Summary */}
        <div className="order-summary">
          <h3>📋 Order Summary</h3>
          <div className="summary-details">
            <div className="summary-item">
              <span>Square Number:</span>
              <strong>#{squareNumber}</strong>
            </div>
            <div className="summary-item">
              <span>Page:</span>
              <strong>Page {pageNumber}</strong>
            </div>
            <div className="summary-item">
              <span>Duration:</span>
              <strong>{duration} days</strong>
            </div>
            <div className="summary-item">
              <span>Daily Rate:</span>
              <strong>£1.00/day</strong>
            </div>
            <div className="summary-item total">
              <span>Total Amount:</span>
              <strong>£{totalAmount}.00</strong>
            </div>
          </div>
        </div>

        {/* Business Form - SIMPLIFIED */}
        <div className="business-form">
          <div className="form-section">
            <h3>🏢 Business Information</h3>
            
            <div className="form-group">
              <label htmlFor="businessName">Business Name *</label>
              <input 
                type="text" 
                id="businessName"
                placeholder="Enter your business name"
                value={businessName}
                onChange={(e) => {
                  setBusinessName(e.target.value);
                  validateForm();
                }}
                autoComplete="organization"
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="contactEmail">Contact Email *</label>
              <input 
                type="email" 
                id="contactEmail"
                placeholder="Enter your email address"
                value={contactEmail}
                onChange={(e) => {
                  setContactEmail(e.target.value);
                  validateForm();
                }}
                autoComplete="email"
              />
            </div>
            
            <div className="form-group">
              <label htmlFor="dealLink">Destination URL (Optional)</label>
              <input 
                type="text" // Changed from "url" to "text" to accept ANY link format
                id="dealLink"
                placeholder="https://any-website.com/any-page"
                value={dealLink}
                onChange={(e) => setDealLink(e.target.value)}
                autoComplete="url"
              />
              <small>Any valid URL - sale page, homepage, contact page, etc. Leave empty if you don't have a website.</small>
            </div>
          </div>

          <div className="form-section">
            <h3>🖼️ Company Logo *</h3>
            
            <div className="form-group">
              <label htmlFor="logoUpload">Upload Logo *</label>
              <input 
                type="file" 
                id="logoUpload"
                accept="image/*"
                onChange={previewLogo}
                autoComplete="off"
              />
              <small>PNG, JPG up to 2MB. Required to continue.</small>
            </div>

            {logoData && (
              <div className="logo-preview">
                <h4>✅ Logo Uploaded Successfully!</h4>
                <img src={logoData} alt="Logo preview" style={{maxWidth: '200px', maxHeight: '200px'}} />
                <p style={{color: 'green', fontWeight: 'bold'}}>You can now continue to payment</p>
              </div>
            )}
          </div>

          {/* Simple Status Display */}
          <div style={{
            background: isFormValid ? '#d4edda' : '#f8d7da',
            padding: '10px',
            borderRadius: '5px',
            margin: '10px 0',
            border: `1px solid ${isFormValid ? '#c3e6cb' : '#f5c6cb'}`
          }}>
            <strong>
              {isFormValid ? '✅ Ready to Continue!' : '❌ Please complete all required fields above'}
            </strong>
          </div>

          <div className="form-actions">
            <button 
              type="button" 
              onClick={() => navigate(-1)}
              style={{
                background: '#6c757d',
                color: 'white',
                padding: '12px 24px',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                marginRight: '10px'
              }}
            >
              ← Back
            </button>
            <button 
              type="button" 
              onClick={handleContinue}
              disabled={!isFormValid}
              style={{
                background: isFormValid ? '#28a745' : '#6c757d',
                color: 'white',
                padding: '12px 24px',
                border: 'none',
                borderRadius: '6px',
                cursor: isFormValid ? 'pointer' : 'not-allowed',
                fontWeight: 'bold'
              }}
            >
              {isFormValid ? "Continue to Payment →" : "Complete Required Fields"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BusinessDetails;
